@page "/login"
@using Microsoft.AspNetCore.Identity
@inject SignInManager<IdentityUser> SignInManager
@inject UserManager<IdentityUser> UserManager
@inject NavigationManager Navigation
@layout MainLayout
@rendermode InteractiveServer

<PageTitle>Login</PageTitle>

<h1>Login</h1>

<div class="row">
    <div class="col-md-4">
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <EditForm Model="loginModel" OnValidSubmit="HandleLogin" FormName="login">
            <div class="mb-3">
                <label class="form-label">Email</label>
                <InputText @bind-Value="loginModel.Email" class="form-control" />
            </div>
            <div class="mb-3">
                <label class="form-label">Password</label>
                <InputText @bind-Value="loginModel.Password" type="password" class="form-control" />
            </div>
            <button type="submit" class="btn btn-primary">Log in</button>
        </EditForm>

        <hr />
        <p class="text-muted">Test accounts:</p>
        <ul class="text-muted small">
            <li>admin@@company.com / Test123!</li>
            <li>manager@@company.com / Test123!</li>
            <li>employee@@company.com / Test123!</li>
        </ul>
    </div>
</div>

@code {
    private LoginModel loginModel = new();
    private string? errorMessage;

    private async Task HandleLogin()
    {
        errorMessage = null;
        var user = await UserManager.FindByEmailAsync(loginModel.Email ?? "");
        if (user is null)
        {
            errorMessage = "Invalid email or password.";
            return;
        }

        var result = await SignInManager.CheckPasswordSignInAsync(user, loginModel.Password ?? "", false);
        if (result.Succeeded)
        {
            // Use cookie-based sign in via navigation to a server endpoint
            Navigation.NavigateTo($"/account/login?email={Uri.EscapeDataString(loginModel.Email!)}&returnUrl={Uri.EscapeDataString(GetReturnUrl())}", forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid email or password.";
        }
    }

    private string GetReturnUrl()
    {
        var uri = Navigation.ToAbsoluteUri(Navigation.Uri);
        var query = System.Web.HttpUtility.ParseQueryString(uri.Query);
        return query["returnUrl"] ?? "/";
    }

    private class LoginModel
    {
        public string? Email { get; set; }
        public string? Password { get; set; }
    }
}

